function PaymentPage() {
  const navigate = useNavigate();

  const [cardNumber, setCardNumber] =
    useState("");

  const [expiry, setExpiry] =
    useState("");

  const [cvv, setCvv] =
    useState("");

  const [name, setName] =
    useState("");

  const [errors, setErrors] =
    useState({});

  const validatePayment = () => {
    let newErrors = {};

    if (
      !/^\d{16}$/.test(
        cardNumber.replace(/\s/g, "")
      )
    ) {
      newErrors.cardNumber =
        "Card number must be 16 digits";
    }

    if (
      !/^\d{2}\/\d{2}$/.test(
        expiry
      )
    ) {
      newErrors.expiry =
        "Expiry must be MM/YY";
    }

    if (!/^\d{3}$/.test(cvv)) {
      newErrors.cvv =
        "CVV must be 3 digits";
    }

    if (
      !/^[A-Za-z\s]+$/.test(
        name
      )
    ) {
      newErrors.name =
        "Name should contain letters only";
    }

    setErrors(newErrors);

    if (
      Object.keys(newErrors)
        .length === 0
    ) {
      alert(
        "Payment Successful!"
      );
    }
  };

  return (
    <div className="payment-page">

      <div
        className="details-back-button"
        onClick={() =>
          navigate(-1)
        }
      >
        ← Back
      </div>

      <div className="payment-card">

        <h1>Checkout</h1>

        <p className="payment-subtitle">
          Secure Payment
        </p>

        <div className="payment-steps">

          <span className="active-step">
            Shipping
          </span>

          <span className="active-step">
            Payment
          </span>

          <span>
            Review
          </span>

        </div>

        <label>
          Card Number
        </label>

        <input
          type="text"
          placeholder="1234567812345678"
          value={cardNumber}
          maxLength="16"
          onChange={(e) =>
            setCardNumber(
              e.target.value
            )
          }
        />

        {errors.cardNumber && (
          <p className="error">
            {errors.cardNumber}
          </p>
        )}

        <div className="payment-row">

          <div>

            <label>
              Expiry Date
            </label>

            <input
              type="text"
              placeholder="MM/YY"
              value={expiry}
              maxLength="5"
              onChange={(e) =>
                setExpiry(
                  e.target.value
                )
              }
            />

            {errors.expiry && (
              <p className="error">
                {errors.expiry}
              </p>
            )}

          </div>

          <div>

            <label>
              CVV
            </label>

            <input
              type="password"
              placeholder="123"
              value={cvv}
              maxLength="3"
              onChange={(e) =>
                setCvv(
                  e.target.value
                )
              }
            />

            {errors.cvv && (
              <p className="error">
                {errors.cvv}
              </p>
            )}

          </div>

        </div>

        <label>
          Cardholder Name
        </label>

        <input
          type="text"
          placeholder="John Doe"
          value={name}
          onChange={(e) =>
            setName(
              e.target.value
            )
          }
        />

        {errors.name && (
          <p className="error">
            {errors.name}
          </p>
        )}

        <div className="other-payments">

          <button className="apple-pay">
            Apple Pay
          </button>

          <button className="paypal">
            PayPal
          </button>

        </div>

        <button
          className="confirm-payment"
          onClick={validatePayment}
        >
          Confirm Payment
        </button>

      </div>
    </div>
  );
}
